const fields = $('Extract Fields').item.json;
const serviceUrl = ($env.SNS_PUBLISHER_SERVICE_URL || '').trim();
const jobId = fields.job_id;
const channelId = fields.channel_id;

function clip(text, maxLen = 300) {
  const normalized = String(text || '').trim();
  if (normalized.length <= maxLen) return normalized;
  return normalized.slice(0, maxLen - 3) + '...';
}

if (!serviceUrl) {
  return {
    json: {
      job_id: jobId,
      channel_id: channelId,
      final_status: 'PUBLISH_FAILED',
      summary_text: `❌ SNS 업로드 실패\n\nJob ID: ${jobId.slice(0, 8)}\n• 시스템 오류: SNS_PUBLISHER_SERVICE_URL is not configured`,
    },
  };
}

let targets = [];
try {
  targets = JSON.parse(fields.targets_json || '[]');
} catch (e) {
  return {
    json: {
      job_id: jobId,
      channel_id: channelId,
      final_status: 'PUBLISH_FAILED',
      summary_text: `❌ SNS 업로드 실패\n\nJob ID: ${jobId.slice(0, 8)}\n• 요청 오류: targets 파싱 실패`,
    },
  };
}

try {
  const endpoint = `${serviceUrl.replace(/\/$/, '')}/publish`;
  const data = await this.helpers.httpRequest({
    method: 'POST',
    url: endpoint,
    headers: { 'Content-Type': 'application/json' },
    body: {
      job_id: jobId,
      video_url: fields.video_url,
      audio_url: fields.audio_url,
      targets,
      title: fields.title,
      description: fields.description,
      caption: fields.caption,
      subtitle_script_text: fields.subtitle_script_text,
      video_filename: fields.video_filename,
    },
    json: true,
    timeout: 30000,
  });

  return {
    json: {
      job_id: jobId,
      channel_id: channelId,
      final_status: data.final_status || 'PUBLISH_FAILED',
      summary_text: data.summary_text || `❌ SNS 업로드 실패\n\nJob ID: ${jobId.slice(0, 8)}\n• 시스템 오류: empty publish response`,
    },
  };
} catch (e) {
  const statusCode = Number((e && (e.statusCode || (e.response && e.response.statusCode))) || 0);
  const responseBody = e && e.response ? e.response.body : undefined;
  const detail = typeof responseBody === 'string'
    ? responseBody
    : (responseBody && typeof responseBody === 'object'
      ? (responseBody.detail || JSON.stringify(responseBody))
      : (e && e.message ? e.message : String(e)));
  const errorLabel = statusCode ? '시스템 오류' : '네트워크 오류';
  return {
    json: {
      job_id: jobId,
      channel_id: channelId,
      final_status: 'PUBLISH_FAILED',
      summary_text: `❌ SNS 업로드 실패\n\nJob ID: ${jobId.slice(0, 8)}\n• ${errorLabel}: ${clip(detail)}`,
    },
  };
}
